// Data layer
interface PostsRepo {
  suspend fun list(): List<Post>
  fun observe(): Flow<List<Post>>
}

class PostsRepoImpl(
  private val remote: PostsApi,           // Retrofit
  private val local: PostsDao              // Room
) : PostsRepo {
  override suspend fun list(): List<Post> {
    val cached = local.all()
    val fresh = runCatching { remote.fetchPosts().map { it.toDomain() } }
    return fresh.fold(
      onSuccess = { local.replaceAll(it.map { p -> p.toEntity() }); it },
      onFailure = { cached.map { it.toDomain() } }
    )
  }
  override fun observe(): Flow<List<Post>> =
    local.observeAll().map { rows -> rows.map { it.toDomain() } }
}

// Domain (optional)
class GetTrendingPosts(private val repo: PostsRepo) {
  suspend operator fun invoke(): List<Post> =
    repo.list().sortedByDescending { it.score }.take(10)
}

// UI
data class HomeUiState(val items: List<Post> = emptyList(), val loading: Boolean = false)

class HomeViewModel(
  private val getTrending: GetTrendingPosts
) : ViewModel() {
  private val _state = MutableStateFlow(HomeUiState(loading = true))
  val state: StateFlow<HomeUiState> = _state.asStateFlow()

  init { reload() }
  fun reload() = viewModelScope.launch {
    _state.value = HomeUiState(loading = true)
    val items = runCatching { getTrending() }.getOrDefault(emptyList())
    _state.value = HomeUiState(items = items, loading = false)
  }
}

// Domain model — owned by domain layer
data class User(val id: Long, val name: String, val avatar: String?)

// Wire DTO — owned by remote
data class UserResponse(val id: Long, val full_name: String, val avatar_url: String?)
fun UserResponse.toDomain() = User(id, full_name, avatar_url)

// Room entity — owned by local
@Entity(tableName = "user")
data class UserEntity(@PrimaryKey val id: Long, val name: String, val avatar: String?)
fun UserEntity.toDomain() = User(id, name, avatar)
fun User.toEntity() = UserEntity(id, name, avatar)

interface UserRepo {
  suspend fun get(id: Long): User
  fun observe(id: Long): Flow<User?>
  suspend fun refreshAll()
}

class UserRepoImpl(
  private val api: UserApi,
  private val dao: UserDao,
  private val ioDispatcher: CoroutineDispatcher
) : UserRepo {

  override suspend fun get(id: Long): User = withContext(ioDispatcher) {
    val cached = dao.byId(id)?.toDomain()
    if (cached != null) return@withContext cached
    val fetched = api.fetchUser(id).toDomain()
    dao.upsert(fetched.toEntity())
    fetched
  }

  override fun observe(id: Long): Flow<User?> =
    dao.observeById(id).map { it?.toDomain() }

  override suspend fun refreshAll() = withContext(ioDispatcher) {
    val users = api.list().map { it.toDomain() }
    dao.replaceAll(users.map { it.toEntity() })
  }
}

