data class CartUiState(
  val items: List<CartItem> = emptyList(),
  val total: Money = Money.ZERO,
  val isLoading: Boolean = false,
  val error: String? = null
)

sealed interface CartAction {
  data class Add(val productId: Long) : CartAction
  data class Remove(val productId: Long) : CartAction
  object Refresh : CartAction
}

class CartViewModel(private val repo: CartRepo) : ViewModel() {
  private val _state = MutableStateFlow(CartUiState())
  val state: StateFlow<CartUiState> = _state.asStateFlow()

  fun onAction(action: CartAction) = viewModelScope.launch {
    when (action) {
      is CartAction.Add    -> mutate { repo.add(action.productId) }
      is CartAction.Remove -> mutate { repo.remove(action.productId) }
      CartAction.Refresh   -> mutate { repo.refresh() }
    }
  }

  private suspend fun mutate(block: suspend () -> Unit) {
    _state.update { it.copy(isLoading = true, error = null) }
    val result = runCatching { block() }
    _state.update {
      if (result.isSuccess) it.copy(isLoading = false, items = repo.snapshot(), total = repo.total())
      else it.copy(isLoading = false, error = result.exceptionOrNull()?.message)
    }
  }
}

@Composable
fun CartScreen(vm: CartViewModel = hiltViewModel()) {
  val state by vm.state.collectAsStateWithLifecycle()
  CartContent(state = state, onAction = vm::onAction)
}

@Composable
fun CartContent(state: CartUiState, onAction: (CartAction) -> Unit) {
  Column {
    Button(onClick = { onAction(CartAction.Refresh) }) { Text("Refresh") }
    LazyColumn { items(state.items) { row ->
      Row {
        Text(row.name)
        Button(onClick = { onAction(CartAction.Remove(row.id)) }) { Text("Remove") }
      }
    } }
    if (state.isLoading) CircularProgressIndicator()
  }
}

// :core-domain (pure Kotlin module)
data class Order(val id: Long, val items: List<OrderItem>, val total: Money)

interface OrderRepository {                        // domain port
  suspend fun get(id: Long): Order
}

class CalculateOrderTotal(private val repo: OrderRepository) {
  suspend operator fun invoke(orderId: Long): Money {
    return repo.get(orderId).items.fold(Money.ZERO) { acc, item -> acc + item.price * item.qty }
  }
}

// :data (depends on :core-domain)
class OrderRepositoryImpl(
  private val api: OrderApi,                       // Retrofit
  private val dao: OrderDao                        // Room
) : OrderRepository {
  override suspend fun get(id: Long): Order =
    dao.byId(id)?.toDomain() ?: api.fetch(id).toDomain().also { dao.upsert(it.toEntity()) }
}

// :app (presentation; depends on :core-domain + :data)
class OrderViewModel(
  private val calcTotal: CalculateOrderTotal
) : ViewModel() { /* uses pure domain calls */ }

// Tests for the use case live in :core-domain — JVM-only, ms-fast
class CalculateOrderTotalTest {
  @Test fun `sums prices`() = runTest {
    val repo = object : OrderRepository { override suspend fun get(id: Long) = sampleOrder() }
    val total = CalculateOrderTotal(repo)(1)
    assertEquals(Money(100), total)
  }
}

