import kotlinx.coroutines.test.*
import kotlin.test.*

class HomeViewModelTest {
  private val testDispatcher = StandardTestDispatcher()

  @BeforeTest
  fun setUp() { Dispatchers.setMain(testDispatcher) }

  @AfterTest
  fun tearDown() { Dispatchers.resetMain() }

  @Test
  fun `reload populates posts`() = runTest(testDispatcher) {
    val repo = FakePostsRepo(posts = listOf(Post(1, "Hello")))
    val vm = HomeViewModel(repo)
    advanceUntilIdle()
    val state = vm.state.value
    assertFalse(state.loading)
    assertEquals(1, state.items.size)
  }

  @Test
  fun `error path surfaces message`() = runTest(testDispatcher) {
    val repo = FakePostsRepo(error = RuntimeException("network"))
    val vm = HomeViewModel(repo)
    advanceUntilIdle()
    assertNotNull(vm.state.value.error)
  }
}

// Fake repo — beats mocks for stability
class FakePostsRepo(
  private val posts: List<Post> = emptyList(),
  private val error: Throwable? = null
) : PostsRepo {
  override suspend fun list(): List<Post> = error?.let { throw it } ?: posts
  override fun observe() = MutableStateFlow(posts)
}

// Compose UI test
@get:Rule val rule = createComposeRule()
@Test fun `tapping Refresh fires onRefresh`() {
  var count = 0
  rule.setContent { CartContent(state = CartUiState(), onAction = { if (it is CartAction.Refresh) count++ }) }
  rule.onNodeWithText("Refresh").performClick()
  assertEquals(1, count)
}
